package main

import (
	"fmt"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
//
// The Lua script must define a global function:
//   calculate_final_price(ctxTable) -> number
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	L := lua.NewState()
	defer L.Close()

	// Load and execute the script (defines calculate_final_price in global scope).
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Fetch the function from global scope.
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table.
	ctxTable := L.NewTable()
	for k, v := range ctx {
		ctxTable.RawSetString(k, lua.LNumber(v))
	}

	// Call calculate_final_price(ctxTable) expecting 1 return value.
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Retrieve and validate return value.
	ret := L.Get(-1)
	L.Pop(1)

	n, ok := ret.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("calculate_final_price did not return a number (got %s)", ret.Type().String())
	}

	return float64(n), nil
}

func main() {
	// Example usage
	script := `
function calculate_final_price(ctx)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`
	price, err := ExecutePricingScript(script, map[string]float64{
		"base_price": 100.0,
		"user_tier":  2,
	})
	if err != nil {
		panic(err)
	}
	fmt.Println(price)
}

