package main

import (
	"context"
	"fmt"
	"math"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
//
// Security hardening:
// - Opens only a minimal set of safe standard libraries (no io/os/debug/package).
// - Enforces a wall-clock timeout via context cancellation.
// - Validates return type and finiteness.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	const timeout = 200 * time.Millisecond

	L := lua.NewState(lua.Options{
		// Skip opening all libs by default; we'll open only the safe subset below.
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Open a minimal subset of standard libraries.
	// NOTE: Do NOT open io/os/debug/package for untrusted scripts.
	lua.OpenBase(L)
	lua.OpenTable(L)
	lua.OpenString(L)
	lua.OpenMath(L)
	lua.OpenCoroutine(L)

	// Remove dangerous functions from base lib.
	L.SetGlobal("dofile", lua.LNil)
	L.SetGlobal("loadfile", lua.LNil)
	L.SetGlobal("load", lua.LNil)

	// Wall-clock timeout using context (supported by gopher-lua).
	execCtx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()
	L.SetContext(execCtx)

	// Load and execute the script.
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope.
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table.
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table.
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		// If timed out, surface a clearer error.
		if execCtx.Err() == context.DeadlineExceeded {
			return 0, fmt.Errorf("script execution timed out")
		}
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack.
	result := L.Get(-1)
	L.Pop(1)

	// Convert result to float64.
	num, ok := result.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	// Basic sanity check: reject NaN/Inf.
	f := float64(num)
	if math.IsNaN(f) || math.IsInf(f, 0) {
		return 0, fmt.Errorf("calculate_final_price returned an invalid number")
	}

	return f, nil
}

func main() {
	// Example usage (optional).
	script := `
function calculate_final_price(ctx)
	if ctx.user_tier >= 2 then
		return ctx.base_price * 0.9
	else
		return ctx.base_price
	end
end
`
	price, err := ExecutePricingScript(script, map[string]float64{
		"base_price": 100,
		"user_tier":  2,
	})
	if err != nil {
		panic(err)
	}
	fmt.Println(price)
}

