func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	if script == "" {
		return 0, errors.New("script is empty")
	}

	const timeout = 100 * time.Millisecond

	// Create a new Lua state WITHOUT opening standard libraries.
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Enforce timeout using a cancellable context + instruction hook (portable).
	execCtx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()
	L.SetContext(execCtx)
	L.SetHook(func(L *lua.LState, ar *lua.Debug) {
		select {
		case <-execCtx.Done():
