func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	const timeout = 50 * time.Millisecond

	// Timeout context
	execCtx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	L := lua.NewState(lua.Options{
		// Skip opening all libs by default; we'll open a safe subset below.
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Open a minimal set of safe standard libraries.
	// Intentionally NOT opening: os, io, debug, package, coroutine.
	lua.OpenBase(L)
	lua.OpenTable(L)
	lua.OpenString(L)
	lua.OpenMath(L)

	// Run the script in a goroutine so we can enforce a hard timeout.
	type result struct {
		val float64
		err error
	}
	ch := make(chan result, 1)

	go func() {
		// Load and execute the script (defines calculate_final_price).
		if err := L.DoString(script); err != nil {
			ch <- result{0, fmt.Errorf("failed to execute Lua script: %w", err)}
			return
		}

		// Get the calculate_final_price function from global scope.
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			ch <- result{0, fmt.Errorf("calculate_final_price is not a function or not defined")}
			return
		}

		// Convert Go context map to Lua table.
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table.
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			ch <- result{0, fmt.Errorf("failed to call calculate_final_price: %w", err)}
			return
		}

