//   - Disable potentially dangerous built-ins (dofile/loadfile/load/require).
//   - Timeout guard (best-effort) to stop long-running scripts.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	if script == "" {
		return 0, errors.New("script is empty")
	}

	// Create a new Lua state without opening standard libraries.
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Provide only safe libraries needed for basic arithmetic and tables.
	// (No os/io/debug/package libs.)
	lua.OpenBase(L)
	lua.OpenTable(L)
	lua.OpenMath(L)
	lua.OpenString(L)

