	disableGlobals := []string{"dofile", "loadfile", "load", "require"}
	for _, name := range disableGlobals {
		L.SetGlobal(name, lua.LNil)
	}

	// Timeout guard to mitigate infinite loops / CPU DoS (best-effort).
	// gopher-lua does not expose SetHook/MaskCount in all versions, so we avoid hooks.
	const timeout = 200 * time.Millisecond
	deadline := time.Now().Add(timeout)

	// Load and execute the script with a time check before/after.
	if time.Now().After(deadline) {
		return 0, fmt.Errorf("script timed out")
	}
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}
	if time.Now().After(deadline) {
		return 0, fmt.Errorf("script timed out")
	}

	// Get the calculate_final_price function from global scope.
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

