		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}
	if time.Now().After(deadline) {
		return 0, fmt.Errorf("script timed out")
	}

	// Get the result from the Lua stack.
	result := L.Get(-1)
	L.Pop(1)

	// Convert result to float64.
	n, ok := result.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	out := float64(n)
	if !isFinite(out) {
		return 0, fmt.Errorf("calculate_final_price returned non-finite number")
	}

