func isFinite(f float64) bool {
	// NaN is the only float not equal to itself.
	if f != f {
		return false
	}
	// +/-Inf checks without importing math.
	const maxFloat = 1.7976931348623157e+308
	return f <= maxFloat && f >= -maxFloat
